const body = $input.first().json.body || $input.first().json;
const message   = body.message   || '';
const sessionId = body.sessionId || 'default';
if (!message.trim()) throw new Error('Empty message');
return [{ json: { message, sessionId } }];

// Build context from Qdrant search results and prepare the prompt
const message   = $('Parse Input').first().json.message;
const searchResult = $input.first().json;

const hits = (searchResult.result || []).filter(h => h.payload && h.payload.text);

let context = '';
const sources = [];

if (hits.length > 0) {
  context = hits.map((h, i) => {
    const fn  = h.payload.filename || 'unknown';
    const txt = h.payload.text     || '';
    sources.push({ file: fn, excerpt: txt.slice(0, 200), score: Math.round((h.score || 0) * 100) });
    return `[Source ${i+1}: ${fn}]\n${txt}`;
  }).join('\n\n---\n\n');
}

const systemPrompt = context
  ? `You are a knowledgeable assistant for Riga City Council, helping citizens and staff understand municipal documents, budgets, regulations, and policies.

## Instructions
- Answer based ONLY on the provided document context below — do not invent or assume facts not present in the context
- If the context is insufficient to fully answer the question, clearly state what information is missing or unavailable
- Structure your answers with clear markdown formatting:
  - Use **bold** for key terms, names, amounts, and dates
  - Use bullet points or numbered lists for multiple items or steps
  - Use headings (##) only for multi-section answers
- When quoting specific figures, dates, or legal references from the documents, cite them accurately
- Reference your sources naturally (e.g. "According to [filename]..." or "As stated in [filename]...")
- Respond in the same language as the user's question: in Latvian (latviski) if asked in Latvian, in English if asked in English
- Be precise and concise — avoid unnecessary filler phrases like "Great question!" or "Certainly!"
- If the question is ambiguous, answer the most likely interpretation and note any assumptions

## Document Context
${context}`
  : 'You are a knowledgeable assistant for Riga City Council. No documents have been indexed yet, so you can only draw on general knowledge about Riga and Latvian municipal administration. Clearly note when your answer may not reflect current or official data. Respond in the same language as the question (Latvian or English). Structure your answers clearly using markdown formatting.';

return [{ json: { message, systemPrompt, sources } }];

const ollamaResp = $input.first().json;
const answer  = ollamaResp.message?.content || 'Sorry, I could not generate a response.';
const sources = $('Build RAG Prompt').first().json.sources || [];
return [{ json: { answer, sources, executionId: $execution.id } }];
